-- Auto-set platform_organization_id from session var on INSERT
CREATE OR REPLACE FUNCTION compensation.set_org_id_from_session()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.platform_organization_id IS NULL
       OR NEW.platform_organization_id = '00000000-0000-0000-0000-000000000000'::uuid THEN
        NEW.platform_organization_id := nullif(current_setting('app.organization_id', true), '')::uuid;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_pay_run_set_org_id ON compensation.pay_run;
CREATE TRIGGER trg_pay_run_set_org_id
    BEFORE INSERT ON compensation.pay_run
    FOR EACH ROW
    EXECUTE FUNCTION compensation.set_org_id_from_session();


